"use client";

import { Bot } from "lucide-react";

/**
 * AIMessageLabel
 *
 * Small disclosure label rendered above (or beside) a message bubble whose
 * `metadata.generated_by === 'ai_agent'`. Tells the customer "this reply was
 * generated by an AI assistant on the shop's behalf" so the source of the
 * message is unambiguous. Universal-rule disclosure (Phase 3 Task 9).
 *
 * Visual: muted violet/lavender to read as informational, not alarming —
 * differentiated from the yellow shop theme without competing.
 */

export interface AIMessageLabelProps {
  className?: string;
}

const TOOLTIP_TEXT =
  "This reply was generated by an AI assistant on the shop's behalf. The shop owner can see and reply to your messages too.";

export function AIMessageLabel({ className = "" }: AIMessageLabelProps) {
  return (
    <div
      title={TOOLTIP_TEXT}
      aria-label={TOOLTIP_TEXT}
      className={`inline-flex items-center gap-1 text-[10px] font-medium text-violet-300/90 mb-1 ${className}`}
    >
      <Bot className="w-3 h-3" aria-hidden="true" />
      <span>AI assistant</span>
    </div>
  );
}
